ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT ?position_title WHERE {
  ?position a :Position .
  ?company a :Companies .
  ?position p:hasCompany ?company .
  ?position p:position_title ?position_title .
  ?position p:trades_jobs ?trades_jobs_w .
  ?position p:trades_jobs ?trades_jobs_w2 .
  ?company p:name ?name_w .
  FILTER((((STR(?trades_jobs_w) = "Construction worker" || STR(?trades_jobs_w2) = "Electrician")) && STR(?name_w) = "yourcompany1"))
} }
  low: { SELECT ?position_title WHERE {
  ?position a :Position .
  ?company a :Companies .
  ?position p:hasCompany ?company .
  ?position p:position_title ?position_title .
  ?position p:trades_jobs ?trades_jobs_w .
  ?position p:trades_jobs ?trades_jobs_w2 .
  ?company p:name ?name_w .
  FILTER((STR(?trades_jobs_w) = "Construction worker" || (STR(?trades_jobs_w2) = "Electrician" && STR(?name_w) = "yourcompany1")))
} }
}
